package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setup() {
        csvFormat = new CSVFormat(',', '"', null, '#', '\\', true, false, "\r\n", "\\N",
                new Object[]{"Header1", "Header2"}, new String[]{"Comment1", "Comment2"}, false, true, false, true, false);
    }

    @Test
    public void testIsEscapeCharacterSet_WhenEscapeCharacterIsNotNull_ExpectTrue() {
        // Given
        csvFormat = csvFormat.withEscape('|');

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertTrue(result);
    }

    @Test
    public void testIsEscapeCharacterSet_WhenEscapeCharacterIsNull_ExpectFalse() {
        // Given
        csvFormat = csvFormat.withEscape(null);

        // When
        boolean result = csvFormat.isEscapeCharacterSet();

        // Then
        assertFalse(result);
    }

    // Add more test cases as needed for optimal coverage

}
